// PARSE P2 & P3 REPORTS - Cheerio-free, forward-compatible
// Original Cheerio selectors in comments above each block.
// Parses self-generated P2/P3 HTML — stable structure under our control.

// ============================================================
// Helper library (extension of the one used in P2/P3 Amazon parsers)
// ============================================================
const decode = (s) => (s || '')
  .replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
  .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(parseInt(n, 10)))
  .replace(/&#[xX]([0-9a-fA-F]+);/g, (_, h) => String.fromCharCode(parseInt(h, 16)));

// Cheerio's .text() — concatenate descendant text nodes (no separator)
const stripTags = (s) => decode(s || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
const escapeRe = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

// Cheerio: $(el).attr('name') — get attribute from a tag string
function attr(tagStr, name) {
  const re = new RegExp('\\b' + escapeRe(name) + '\\s*=\\s*(["\'])((?:(?!\\1).)*)\\1', 'i');
  const m = tagStr.match(re);
  return m ? decode(m[2]) : '';
}

// Find a complete element (opening tag + content + closing tag) starting at openMatch
// Returns { tag, openTag, inner, full, attrs }
function elementAt(html, openMatch) {
  const tag = openMatch[1].toLowerCase();
  const startIdx = openMatch.index + openMatch[0].length;
  const openRe = new RegExp('<' + tag + '\\b', 'gi');
  const closeRe = new RegExp('</' + tag + '\\s*>', 'gi');
  let depth = 1;
  let i = startIdx;
  while (i < html.length && depth > 0) {
    openRe.lastIndex = i;
    closeRe.lastIndex = i;
    const o = openRe.exec(html);
    const c = closeRe.exec(html);
    if (!c) break;
    if (o && o.index < c.index) { depth++; i = o.index + 1; }
    else { depth--; if (depth === 0) {
      return {
        tag,
        openTag: openMatch[0],
        inner: html.substring(startIdx, c.index),
        full: html.substring(openMatch.index, c.index + c[0].length)
      };
    } i = c.index + 1; }
  }
  return null;
}

// Cheerio: $('.classname') — find all elements with a class (across all tag types)
function elementsByClass(html, className) {
  const re = new RegExp('<(\\w+)\\b[^>]*?\\bclass\\s*=\\s*(["\'])(?:[^"\']*\\s)?' + escapeRe(className) + '(?:\\s[^"\']*)?\\2[^>]*>', 'gi');
  const results = [];
  let m;
  while ((m = re.exec(html)) !== null) {
    const el = elementAt(html, m);
    if (el) {
      results.push(el);
      re.lastIndex = m.index + el.full.length;  // skip past consumed element
    }
  }
  return results;
}

// Cheerio: $('selector1, selector2') — union of multiple class selectors
function elementsByAnyClass(html, classNames) {
  const all = [];
  for (const cn of classNames) all.push(...elementsByClass(html, cn));
  // Sort by position to maintain document order
  all.sort((a, b) => html.indexOf(a.full) - html.indexOf(b.full));
  return all;
}

// Cheerio: $(scope).find('h4').first().text()
function firstTagText(scopeHtml, tagName) {
  const re = new RegExp('<' + tagName + '\\b[^>]*>', 'i');
  const m = scopeHtml.match(re);
  if (!m) return '';
  const matchObj = Object.assign([m[0], tagName], { index: m.index, input: scopeHtml });
  const el = elementAt(scopeHtml, matchObj);
  return el ? stripTags(el.inner) : '';
}

// Cheerio: $(scope).find('h4, strong').first().text() — union of tag names
function firstAnyTagText(scopeHtml, tagNames) {
  let bestIdx = Infinity;
  let bestText = '';
  for (const tag of tagNames) {
    const re = new RegExp('<' + tag + '\\b[^>]*>', 'i');
    const m = scopeHtml.match(re);
    if (m && m.index < bestIdx) {
      const matchObj = Object.assign([m[0], tag], { index: m.index, input: scopeHtml });
      const el = elementAt(scopeHtml, matchObj);
      if (el) { bestIdx = m.index; bestText = stripTags(el.inner); }
    }
  }
  return bestText;
}

// Cheerio: $(scope).find('tag') — all elements of a tag
function allByTag(scopeHtml, tagName) {
  const re = new RegExp('<' + tagName + '\\b[^>]*>', 'gi');
  const results = [];
  let m;
  while ((m = re.exec(scopeHtml)) !== null) {
    const matchObj = Object.assign([m[0], tagName], { index: m.index, input: scopeHtml });
    const el = elementAt(scopeHtml, matchObj);
    if (el) {
      results.push(el);
      re.lastIndex = m.index + el.full.length;
    } else {
      re.lastIndex = m.index + m[0].length;
    }
  }
  return results;
}

// Cheerio: $(scope).find('.class').first().text() — within a scope
function firstByClassText(scopeHtml, className) {
  const els = elementsByClass(scopeHtml, className);
  return els.length > 0 ? stripTags(els[0].inner) : '';
}

// Cheerio: $(scope).find('.class').text() — concat text of all matches
function allByClassText(scopeHtml, classNames) {
  const list = Array.isArray(classNames) ? classNames : [classNames];
  let text = '';
  for (const cn of list) {
    for (const el of elementsByClass(scopeHtml, cn)) text += stripTags(el.inner);
  }
  return text;
}

// Cheerio: $(el).attr('class')
function classOf(el) { return attr(el.openTag, 'class'); }

// Cheerio: $(el).text()
function textOf(el) { return stripTags(el.inner); }

// Cheerio: $('img').each(...).attr('src') — list all img src values
function imgSrcs(html) {
  const re = /<img\b[^>]*>/gi;
  const srcs = [];
  let m;
  while ((m = re.exec(html)) !== null) srcs.push(attr(m[0], 'src'));
  return srcs;
}

// Get attribute on any inner tag where attr value contains substring
// Cheerio: $(el).find('[style*="background"]').attr('style')
function findAttrContaining(scopeHtml, attrName, contains) {
  const re = new RegExp('<\\w+\\b[^>]*?\\b' + escapeRe(attrName) + '\\s*=\\s*(["\'])([^"\']*' + escapeRe(contains) + '[^"\']*)\\1[^>]*>', 'i');
  const m = scopeHtml.match(re);
  return m ? decode(m[2]) : '';
}

// ============================================================
// MAIN — load HTML from binary
// ============================================================
const item = $input.first();
const context = $('Extract Form Files').first().json;

let p2Html = '';
let p3Html = '';

console.log('Binary keys available:', Object.keys(item.binary || {}));

if (item.binary?.p2_binary) {
  const p2Buffer = await this.helpers.getBinaryDataBuffer(0, 'p2_binary');
  p2Html = p2Buffer.toString('utf8');
  console.log('P2 HTML loaded, length:', p2Html.length);
}

if (item.binary?.p3_binary) {
  const p3Buffer = await this.helpers.getBinaryDataBuffer(0, 'p3_binary');
  p3Html = p3Buffer.toString('utf8');
  console.log('P3 HTML loaded, length:', p3Html.length);
}

// ============================================================
// PARSE P2 (Market Trend Report)
// ============================================================
let p2Data = {
  keyInsight: '',
  marketMetrics: { size2025: '', size2033: '', cagr: '' },
  microSegments: [],
  colorPalette: [],
  risks: [],
  recommendations: [],
  moodboardImages: [],
  attributeBars: { materials: [], sizes: [], colors: [], prices: [] }
};

try {
  if (p2Html) {
    // Cheerio: $('.key-insight p').first().text() || $('.summary-hero .key-insight p').first().text() || $('.executive-summary p').first().text()
    const keyInsightEls = [
      ...elementsByClass(p2Html, 'key-insight'),
      ...elementsByClass(p2Html, 'executive-summary')
    ];
    for (const el of keyInsightEls) {
      const txt = firstTagText(el.inner, 'p');
      if (txt) { p2Data.keyInsight = txt; break; }
    }
    console.log('P2 Key Insight:', p2Data.keyInsight.substring(0, 100));

    // Cheerio: $('.profile-card').each — Market Metrics
    for (const card of elementsByClass(p2Html, 'profile-card')) {
      const heading = firstTagText(card.inner, 'h4').toLowerCase();
      const value = firstTagText(card.inner, 'p');
      if (heading.includes('market size') && heading.includes('2025')) p2Data.marketMetrics.size2025 = value;
      else if (heading.includes('projected') && heading.includes('2033')) p2Data.marketMetrics.size2033 = value;
      else if (heading.includes('cagr')) p2Data.marketMetrics.cagr = value;
    }
    console.log('P2 Market Metrics:', JSON.stringify(p2Data.marketMetrics));

    // Cheerio: $('.segment-card').each — Micro-Segments
    for (const card of elementsByClass(p2Html, 'segment-card')) {
      const name = firstTagText(card.inner, 'h4');
      const tier = firstByClassText(card.inner, 'segment-badge');
      // Cheerio: .find('.segment-description, p').first()
      let description = firstByClassText(card.inner, 'segment-description');
      if (!description) description = firstTagText(card.inner, 'p');
      // .find('.segment-meta').text()
      const metaText = allByClassText(card.inner, 'segment-meta');
      const colorsMatch = metaText.match(/🎨\s*([^\ud83c]+)/);
      const useCasesMatch = metaText.match(/🏠\s*(.+)/);
      if (name) {
        p2Data.microSegments.push({
          name: name.replace(/^\d+\.\s*/, ''),
          tier: tier || 'Emerging',
          description: description.substring(0, 300),
          colors: colorsMatch?.[1]?.trim() || '',
          useCases: useCasesMatch?.[1]?.trim() || ''
        });
      }
    }
    console.log('P2 Segments found:', p2Data.microSegments.length);

    // Cheerio: $('.color-swatch, .color-card').each — Color Palette
    for (const el of elementsByAnyClass(p2Html, ['color-swatch', 'color-card'])) {
      const style = attr(el.openTag, 'style') || '';
      const innerStyle = findAttrContaining(el.inner, 'style', 'background') || '';
      const allStyles = style + ' ' + innerStyle;
      const hexMatch = allStyles.match(/#[A-Fa-f0-9]{6}/);
      let name = firstByClassText(el.inner, 'swatch-label') || firstByClassText(el.inner, 'color-name');
      if (!name) name = stripTags(el.inner).split('\n')[0];
      if (hexMatch && p2Data.colorPalette.length < 6) {
        p2Data.colorPalette.push({
          hex: hexMatch[0],
          name: name.substring(0, 30) || `Color ${p2Data.colorPalette.length + 1}`
        });
      }
    }
    console.log('P2 Colors found:', p2Data.colorPalette.length);

    // Cheerio: $('.risk-card').each — Risks
    for (const card of elementsByClass(p2Html, 'risk-card')) {
      let title = firstTagText(card.inner, 'h4') || firstByClassText(card.inner, 'risk-title');
      const className = classOf(card);
      let severity = 'medium';
      if (className.includes('high') || className.includes('risk-high')) severity = 'high';
      else if (className.includes('low') || className.includes('risk-low')) severity = 'low';
      let description = firstTagText(card.inner, 'p') || firstByClassText(card.inner, 'risk-description');
      const mitigation = allByClassText(card.inner, 'risk-mitigation').replace(/Mitigation:?/gi, '').trim();
      if (title) p2Data.risks.push({ title, severity, description: description.substring(0, 200), mitigation });
    }
    console.log('P2 Risks found:', p2Data.risks.length);

    // Cheerio: $('.rec-item, .recommendation-card').each — Recommendations
    for (const card of elementsByAnyClass(p2Html, ['rec-item', 'recommendation-card'])) {
      // Cheerio: .find('h4, strong').first()
      const title = firstAnyTagText(card.inner, ['h4', 'strong']);
      const description = firstTagText(card.inner, 'p');
      const impact = firstByClassText(card.inner, 'rec-impact');
      if (title && p2Data.recommendations.length < 5) {
        p2Data.recommendations.push({ title, description: description.substring(0, 200), impact });
      }
    }
    console.log('P2 Recommendations found:', p2Data.recommendations.length);

    // Cheerio: $('img').each — Moodboard Images (data:image)
    for (const src of imgSrcs(p2Html)) {
      if (src.startsWith('data:image') && p2Data.moodboardImages.length < 4) {
        p2Data.moodboardImages.push(src);
      }
    }
    console.log('P2 Moodboard images found:', p2Data.moodboardImages.length);

    // Cheerio: $('.attribute-card').each — Attribute Distribution Bars
    for (const card of elementsByClass(p2Html, 'attribute-card')) {
      const cardTitle = firstTagText(card.inner, 'h3').toLowerCase();
      const bars = [];
      for (const row of elementsByClass(card.inner, 'data-row')) {
        const label = firstByClassText(row.inner, 'label');
        const value = firstByClassText(row.inner, 'value');
        // .find('.bar').attr('style')
        const barEls = elementsByClass(row.inner, 'bar');
        const barStyle = barEls.length > 0 ? attr(barEls[0].openTag, 'style') : '';
        const widthMatch = barStyle.match(/([\d.]+)%/);
        if (label) {
          bars.push({
            label,
            value: value || '',
            width: widthMatch ? parseFloat(widthMatch[1]) : 0
          });
        }
      }
      if (cardTitle.includes('material')) p2Data.attributeBars.materials = bars;
      else if (cardTitle.includes('size')) p2Data.attributeBars.sizes = bars;
      else if (cardTitle.includes('color') || cardTitle.includes('pattern')) p2Data.attributeBars.colors = bars;
      else if (cardTitle.includes('price')) p2Data.attributeBars.prices = bars;
    }
    console.log('P2 Attribute bars - materials:', p2Data.attributeBars.materials.length,
                ', sizes:', p2Data.attributeBars.sizes.length,
                ', colors:', p2Data.attributeBars.colors.length);
  }
} catch (e) {
  console.error('P2 Parse Error:', e.message);
}

// ============================================================
// PARSE P3 (Competitor Analysis Report)
// ============================================================
let p3Data = {
  keyInsight: '',
  scope: { amazonProducts: 0, walmartProducts: 0, wayfairProducts: 0 },
  pricePositioning: {
    wayfair: { avg: '', min: '', max: '' },
    amazon: { avg: '', min: '', max: '' },
    walmart: { avg: '', min: '', max: '' }
  },
  comparisonTable: [],
  priceBands: { budget: {}, mid: {}, premium: {} },
  priceGaps: [],
  opportunities: [],
  quickWins: [],
  strategicInitiatives: [],
  suppliers: [],
  discountTiers: []
};

try {
  if (p3Html) {
    // Cheerio: $('.key-insight p').first().text()
    const kiEls = elementsByClass(p3Html, 'key-insight');
    if (kiEls.length > 0) p3Data.keyInsight = firstTagText(kiEls[0].inner, 'p');
    console.log('P3 Key Insight:', p3Data.keyInsight.substring(0, 100));

    // Cheerio: $('.scope-card, .scope-section').text() — Scope Product Counts
    const scopeText = allByClassText(p3Html, ['scope-card', 'scope-section']);
    const amazonMatch = scopeText.match(/Amazon[^\d]*(\d+)/i);
    const walmartMatch = scopeText.match(/Walmart[^\d]*(\d+)/i);
    const wayfairMatch = scopeText.match(/Wayfair[^\d]*(\d+)/i);
    if (amazonMatch) p3Data.scope.amazonProducts = parseInt(amazonMatch[1]);
    if (walmartMatch) p3Data.scope.walmartProducts = parseInt(walmartMatch[1]);
    if (wayfairMatch) p3Data.scope.wayfairProducts = parseInt(wayfairMatch[1]);
    console.log('P3 Scope:', JSON.stringify(p3Data.scope));

    // Cheerio: $('.comparison-table tbody tr').each — Price Positioning + Comparison Table
    const tableScopes = elementsByClass(p3Html, 'comparison-table');
    const rows = [];
    for (const ts of tableScopes) {
      // Find tbody, then iterate tr
      const tbodyEls = allByTag(ts.inner, 'tbody');
      const tbodyHtml = tbodyEls.length > 0 ? tbodyEls[0].inner : ts.inner;
      for (const tr of allByTag(tbodyHtml, 'tr')) rows.push(tr);
    }
    for (const row of rows) {
      const cells = allByTag(row.inner, 'td');
      if (cells.length < 1) continue;
      const attribute = stripTags(cells[0].inner).toLowerCase();
      if (attribute.includes('price') && cells.length >= 4) {
        const grab = (txt) => {
          const avg = txt.match(/Avg:\s*\$([\d,.]+)/i);
          const mn = txt.match(/Min:\s*\$([\d,.]+)/i);
          const mx = txt.match(/Max:\s*\$([\d,.]+)/i);
          return {
            avg: avg ? '$' + avg[1] : '',
            min: mn ? '$' + mn[1] : '',
            max: mx ? '$' + mx[1] : ''
          };
        };
        const wf = grab(stripTags(cells[1].inner));
        const am = grab(stripTags(cells[2].inner));
        const wm = grab(stripTags(cells[3].inner));
        if (wf.avg) p3Data.pricePositioning.wayfair.avg = wf.avg;
        if (wf.min) p3Data.pricePositioning.wayfair.min = wf.min;
        if (wf.max) p3Data.pricePositioning.wayfair.max = wf.max;
        if (am.avg) p3Data.pricePositioning.amazon.avg = am.avg;
        if (am.min) p3Data.pricePositioning.amazon.min = am.min;
        if (am.max) p3Data.pricePositioning.amazon.max = am.max;
        if (wm.avg) p3Data.pricePositioning.walmart.avg = wm.avg;
        if (wm.min) p3Data.pricePositioning.walmart.min = wm.min;
        if (wm.max) p3Data.pricePositioning.walmart.max = wm.max;
      }
    }
    console.log('P3 Price Positioning:', JSON.stringify(p3Data.pricePositioning));

    // Comparison Table rows
    for (const row of rows) {
      const cells = allByTag(row.inner, 'td');
      if (cells.length >= 5) {
        const attribute = stripTags(cells[0].inner);
        const wayfair = stripTags(cells[1].inner).substring(0, 200);
        const amazon = stripTags(cells[2].inner).substring(0, 200);
        const walmart = stripTags(cells[3].inner).substring(0, 200);
        const winner = stripTags(cells[4].inner);
        if (attribute) p3Data.comparisonTable.push({ attribute, wayfair, amazon, walmart, winner });
      }
    }
    console.log('P3 Comparison rows:', p3Data.comparisonTable.length);

    // Cheerio: $('.band').each — Price Bands
    for (const el of elementsByClass(p3Html, 'band')) {
      const text = stripTags(el.inner);
      const values = text.match(/W:\s*(\d+)\s*\|\s*A:\s*(\d+)\s*\|\s*Wm:\s*(\d+)/i);
      if (text.toLowerCase().includes('budget') && values) {
        p3Data.priceBands.budget = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      } else if (text.toLowerCase().includes('mid') && values) {
        p3Data.priceBands.mid = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      } else if (text.toLowerCase().includes('premium') && values) {
        p3Data.priceBands.premium = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      }
    }
    console.log('P3 Price Bands:', JSON.stringify(p3Data.priceBands));

    // Cheerio: $('.gap').each — Price Gaps Heatmap
    for (const el of elementsByClass(p3Html, 'gap')) {
      const spans = allByTag(el.inner, 'span');
      const range = spans.length > 0 ? stripTags(spans[0].inner) : '';
      const description = spans.length > 0 ? stripTags(spans[spans.length - 1].inner) : '';
      const className = classOf(el);
      let level = 'moderate';
      if (className.includes('hot')) level = 'hot';
      else if (className.includes('warm')) level = 'warm';
      else if (className.includes('cool') || className.includes('open')) level = 'open';
      if (range) p3Data.priceGaps.push({ range, description, level });
    }
    console.log('P3 Price Gaps:', p3Data.priceGaps.length);

    // Cheerio: $('.whitespace-opportunities .opportunity-card, .opportunity-cards .opportunity-card').each
    // Cheerio dedupes comma-selector matches and iterates in DOCUMENT order.
    const oppScopes = [
      ...elementsByClass(p3Html, 'whitespace-opportunities'),
      ...elementsByClass(p3Html, 'opportunity-cards')
    ];
    const oppMap = new Map();
    for (const sc of oppScopes) {
      for (const card of elementsByClass(sc.inner, 'opportunity-card')) {
        const pos = p3Html.indexOf(card.full);  // global position dedupes correctly
        if (pos >= 0 && !oppMap.has(pos)) oppMap.set(pos, { ...card, pos });
      }
    }
    const oppCards = [...oppMap.values()].sort((a, b) => a.pos - b.pos);
    for (const el of oppCards) {
      const title = firstTagText(el.inner, 'h4').replace(/[🎯⚡📊💡🔥]/g, '').trim();
      const description = firstTagText(el.inner, 'p');
      const className = classOf(el);
      const priority = className.includes('high') ? 'high' : (className.includes('low') ? 'low' : 'medium');
      if (title && p3Data.opportunities.length < 6) {
        p3Data.opportunities.push({ title, description: description.substring(0, 250), priority });
      }
    }
    console.log('P3 Opportunities:', p3Data.opportunities.length);

    // Cheerio: $('.quick-wins .rec-card').each
    const qwScopes = elementsByClass(p3Html, 'quick-wins');
    const qwCards = [];
    for (const sc of qwScopes) qwCards.push(...elementsByClass(sc.inner, 'rec-card'));
    for (const el of qwCards) {
      const title = firstTagText(el.inner, 'h4').replace(/^\d+\.\s*/, '');
      const description = firstTagText(el.inner, 'p');
      const priority = classOf(el).includes('high') ? 'high' : 'medium';
      if (title) p3Data.quickWins.push({ title, description: description.substring(0, 200), priority });
    }
    console.log('P3 Quick Wins:', p3Data.quickWins.length);

    // Cheerio: $('.strategic-plays .rec-card, .strategic-initiatives .rec-card').each — dedupe + document order
    const stratScopes = [
      ...elementsByClass(p3Html, 'strategic-plays'),
      ...elementsByClass(p3Html, 'strategic-initiatives')
    ];
    const stratMap = new Map();
    for (const sc of stratScopes) {
      for (const card of elementsByClass(sc.inner, 'rec-card')) {
        const pos = p3Html.indexOf(card.full);
        if (pos >= 0 && !stratMap.has(pos)) stratMap.set(pos, { ...card, pos });
      }
    }
    const stratCards = [...stratMap.values()].sort((a, b) => a.pos - b.pos);
    for (const el of stratCards) {
      const title = firstTagText(el.inner, 'h4').replace(/^\d+\.\s*/, '');
      const description = firstTagText(el.inner, 'p');
      const priority = classOf(el).includes('high') ? 'high' : 'medium';
      if (title) p3Data.strategicInitiatives.push({ title, description: description.substring(0, 200), priority });
    }
    console.log('P3 Strategic Initiatives:', p3Data.strategicInitiatives.length);

    // Cheerio: $('.supplier-identification table tbody tr, .suppliers-observed table tbody tr').each — dedupe + document order
    const supScopes = [
      ...elementsByClass(p3Html, 'supplier-identification'),
      ...elementsByClass(p3Html, 'suppliers-observed')
    ];
    const supMap = new Map();
    for (const sc of supScopes) {
      const tables = allByTag(sc.inner, 'table');
      for (const tb of tables) {
        const tbodies = allByTag(tb.inner, 'tbody');
        const bodyHtml = tbodies.length > 0 ? tbodies[0].inner : tb.inner;
        for (const tr of allByTag(bodyHtml, 'tr')) {
          const pos = p3Html.indexOf(tr.full);
          if (pos >= 0 && !supMap.has(pos)) supMap.set(pos, { ...tr, pos });
        }
      }
    }
    const supRows = [...supMap.values()].sort((a, b) => a.pos - b.pos);
    for (const row of supRows) {
      const cells = allByTag(row.inner, 'td');
      if (cells.length >= 4) {
        const name = stripTags(cells[0].inner);
        const platform = stripTags(cells[1].inner);
        if (name.length > 50 || platform.startsWith('$')) continue;
        if (name && p3Data.suppliers.length < 10) {
          // Get website from cell 4's <a href>
          let website = '';
          if (cells.length >= 5) {
            const aRe = /<a\b[^>]*?\bhref\s*=\s*(["'])((?:(?!\1).)*)\1[^>]*>/i;
            const aMatch = cells[4].inner.match(aRe);
            if (aMatch) website = decode(aMatch[2]);
          }
          p3Data.suppliers.push({
            name,
            platform,
            knownFor: stripTags(cells[2].inner).substring(0, 100),
            priceRange: stripTags(cells[3].inner),
            website
          });
        }
      }
    }
    console.log('P3 Suppliers:', p3Data.suppliers.length);

    // Cheerio: $('.discount-tier').each
    for (const el of elementsByClass(p3Html, 'discount-tier')) {
      const spans = allByTag(el.inner, 'span');
      const label = spans.length > 0 ? stripTags(spans[0].inner) : '';
      const values = spans.length > 0 ? stripTags(spans[spans.length - 1].inner) : '';
      const match = values.match(/W:\s*(\d+)\s*\|\s*Wm:\s*(\d+)/i);
      if (label && match) {
        p3Data.discountTiers.push({
          label,
          wayfair: parseInt(match[1]),
          walmart: parseInt(match[2])
        });
      }
    }
    console.log('P3 Discount Tiers:', p3Data.discountTiers.length);
  }
} catch (e) {
  console.error('P3 Parse Error:', e.message);
}

