// Build context for Parse P2 & P3 Reports:
//   json: { categoryName, dateFolderName, templateHtml }
//   binary: { p2_binary, p3_binary }

const form = $('Upload Form').first().json;
const templateHtml = $input.first().json.data || $input.first().json.body || '';

const categoryName = form['Product Category'] || 'Unknown';
const dateFolderName = new Date().toISOString().split('T')[0];

// File uploads from n8n's Form Trigger arrive as binary on the form item.
// Look them up by their field labels.
function extractFileToBase64(fieldLabel) {
  const upload = form[fieldLabel];
  if (!upload) return null;
  // upload.data is base64 if the form trigger captured the file
  if (typeof upload === 'string') {
    return Buffer.from(upload, 'utf8').toString('base64');
  }
  if (upload.data) {
    return upload.data;  // already base64
  }
  return null;
}

// Form Trigger places file uploads on the binary side too — try both
const formBinary = $('Upload Form').first().binary || {};

function makeBinary(label) {
  // 1) Prefer binary attached by Form Trigger
  for (const k of Object.keys(formBinary)) {
    if (formBinary[k] && formBinary[k].fileName && formBinary[k].fileName.toLowerCase().includes(label.toLowerCase().split(' ')[0])) {
      return formBinary[k];
    }
  }
  // 2) Fall back to scanning numbered binary keys
  for (const k of ['data', 'data_0', 'data_1', label]) {
    if (formBinary[k]) return formBinary[k];
  }
  // 3) Fall back to base64 in JSON form field
  const b64 = extractFileToBase64(label);
  if (b64) {
    return {
      data: b64,
      mimeType: 'text/html',
      fileName: label.replace(/[^a-zA-Z0-9]+/g, '_') + '.html',
      fileExtension: 'html',
    };
  }
  return null;
}

// Form Trigger uses indexed binary keys 'data_0', 'data_1' for files
// when multiple file fields exist; try those explicitly.
const binaryKeys = Object.keys(formBinary);
console.log('Form binary keys:', binaryKeys);

// Best effort: take first 2 binary entries (P2 then P3)
const ordered = binaryKeys.sort();
const p2_binary = ordered.length > 0 ? formBinary[ordered[0]] : null;
const p3_binary = ordered.length > 1 ? formBinary[ordered[1]] : null;

const out = {
  json: {
    categoryName,
    dateFolderName,
    templateHtml,
  },
  binary: {}
};
if (p2_binary) out.binary.p2_binary = p2_binary;
if (p3_binary) out.binary.p3_binary = p3_binary;

console.log('Output binary keys:', Object.keys(out.binary));
console.log('Template HTML length:', templateHtml.length);

return [out];
